-- ════════════════════════════════════════════════════════════════
-- 032 — LNMPE 2025 national medication catalog (global medications)
-- ════════════════════════════════════════════════════════════════
--
-- Source: public/files/LNMPE-2025.pdf (scanned; manually OCR'd).
-- GLOBAL medications table only. Does NOT touch clinic_medication_inventory
-- or medication_batches; stores NO stock quantities. Additive + idempotent.
--
-- Rows extracted: 821 | medications upserted: 800 | skipped(non-med): 6 | duplicates: 15 | uncertain OCR: 5

-- ── Additive metadata columns (safe if already present) ──────────
ALTER TABLE public.medications ADD COLUMN IF NOT EXISTS source            TEXT;
ALTER TABLE public.medications ADD COLUMN IF NOT EXISTS therapeutic_class TEXT;
ALTER TABLE public.medications ADD COLUMN IF NOT EXISTS normalized_name   TEXT;
CREATE INDEX IF NOT EXISTS idx_medications_source ON public.medications(source);
-- Enforce LNMPE dedup on the normalized key WITHOUT affecting other sources.
CREATE UNIQUE INDEX IF NOT EXISTS uq_medications_lnmpe_norm
  ON public.medications(normalized_name) WHERE source = 'LNMPE 2025';

-- ── Upsert catalog (name is UNIQUE → ON CONFLICT preserves the id) ─
ON CONFLICT (name) DO UPDATE SET
  strength          = EXCLUDED.strength,
  dosage_form       = EXCLUDED.dosage_form,
  therapeutic_class = EXCLUDED.therapeutic_class,
  source            = EXCLUDED.source,
  normalized_name   = EXCLUDED.normalized_name,
  is_active         = TRUE,
  updated_at        = NOW();

NOTIFY pgrst, 'reload schema';
